      syntax:`class TrieNode{TrieNode[] c=new TrieNode[26]; boolean end;}\nclass Trie{\n    TrieNode root=new TrieNode();\n    void insert(String w){...}\n    boolean startsWith(String p){...}\n}`,
      code:`void insert(String w){\n    TrieNode n=root;\n    for(char c:w.toCharArray()){\n        int i=c-'a';\n        if(n.c[i]==null) n.c[i]=new TrieNode();\n        n=n.c[i];\n    }\n    n.end=true;\n}\nboolean startsWith(String p){\n    TrieNode n=root;\n    for(char c:p.toCharArray()){\n        if(n.c[c-'a']==null) return false;\n        n=n.c[c-'a'];\n    }\n    return true;\n}`,
