      syntax:`Queue<Integer> q=new LinkedList<>();\nq.offer(start); vis[start]=true;\nwhile(!q.isEmpty()){\n    int u=q.poll();\n    for(int v:adj.get(u))\n        if(!vis[v]){vis[v]=true;q.offer(v);}\n}`,
      code:`static void bfs(List<List<Integer>> adj,int start){\n    boolean[] vis=new boolean[adj.size()];\n    Queue<Integer> q=new LinkedList<>();\n    q.offer(start); vis[start]=true;\n    while(!q.isEmpty()){\n        int u=q.poll();\n        System.out.print(u+" ");\n        for(int v:adj.get(u))\n            if(!vis[v]){vis[v]=true;q.offer(v);}\n    }\n}`,
