      code:`List<String> names = new ArrayList<>(List.of("Alice","Bob","Charlie","Dave"));\n\n// Remove names shorter than 4 chars — safely\nIterator<String> it = names.iterator();\nwhile (it.hasNext()) {\n    if (it.next().length() < 4) it.remove();\n}\nSystem.out.println(names);   // [Alice, Charlie, Dave]\n\n// ListIterator — replace every element in place\nListIterator<String> lit = names.listIterator();\nwhile (lit.hasNext()) {\n    lit.set(lit.next().toUpperCase());\n}\nSystem.out.println(names);   // [ALICE, CHARLIE, DAVE]`,
